using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities for the research agent.
/// Uses DuckDuckGo HTML search to avoid requiring API keys.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public AIFunction AsAIFunction() => AIFunctionFactory.Create(
        SearchWebAsync, nameof(SearchWebAsync),
        "Search the web for information on a topic. Returns a list of result snippets.");

    [Description("Search the web for information on a topic. Returns a list of result snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        using var response = await _httpClient.SendAsync(request, cancellationToken);
        response.EnsureSuccessStatusCode();

        var html = await response.Content.ReadAsStringAsync(cancellationToken);

        var snippets = ExtractSnippets(html);
        if (snippets.Count == 0)
        {
            return $"No results found for '{query}'.";
        }

        return $"Search results for '{query}':\n\n" +
               string.Join("\n\n", snippets.Select((s, i) => $"[{i + 1}] {s}"));
    }

    private static List<string> ExtractSnippets(string html)
    {
        var snippets = new List<string>();

        // Extract result snippets from DuckDuckGo HTML response
        var snippetMatches = SnippetPattern().Matches(html);
        foreach (Match match in snippetMatches)
        {
            var text = StripHtml(WebUtility.HtmlDecode(match.Groups[1].Value)).Trim();
            if (!string.IsNullOrWhiteSpace(text) && text.Length > 20)
            {
                snippets.Add(text);
            }

            if (snippets.Count >= 8)
                break;
        }

        // Fallback: extract from generic result blocks
        if (snippets.Count == 0)
        {
            var resultMatches = ResultTextPattern().Matches(html);
            foreach (Match match in resultMatches)
            {
                var text = StripHtml(WebUtility.HtmlDecode(match.Groups[1].Value)).Trim();
                if (!string.IsNullOrWhiteSpace(text) && text.Length > 30)
                {
                    snippets.Add(text.Length > 300 ? text[..300] + "..." : text);
                }

                if (snippets.Count >= 5)
                    break;
            }
        }

        return snippets;
    }

    private static string StripHtml(string input) =>
        HtmlTagPattern().Replace(input, "").Trim();

    [GeneratedRegex("""class="result__snippet"[^>]*>(.*?)</""", RegexOptions.Singleline)]
    private static partial Regex SnippetPattern();

    [GeneratedRegex("""class="result__body"[^>]*>(.*?)</div>""", RegexOptions.Singleline)]
    private static partial Regex ResultTextPattern();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagPattern();
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent.
/// Stores notes in memory for use during a research session.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public IReadOnlyList<AIFunction> AsAIFunctions() =>
    [
        AIFunctionFactory.Create(SaveNote, nameof(SaveNote),
            "Save a research note with a title and content for later reference."),
        AIFunctionFactory.Create(GetAllNotes, nameof(GetAllNotes),
            "Retrieve all saved research notes."),
        AIFunctionFactory.Create(SearchNotes, nameof(SearchNotes),
            "Search through saved notes by keyword."),
    ];

    [Description("Save a research note with a title and content for later reference.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content/body of the note")] string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        return $"Note '{title}' saved successfully (total notes: {_notes.Count}).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n---\n\n",
            _notes.Select((n, i) =>
                $"Note {i + 1}: {n.Title}\n{n.Content}"));
    }

    [Description("Search through saved notes by keyword.")]
    public string SearchNotes(
        [Description("The keyword to search for in notes")] string keyword)
    {
        var matches = _notes
            .Where(n => n.Title.Contains(keyword, StringComparison.OrdinalIgnoreCase)
                     || n.Content.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            .ToList();

        if (matches.Count == 0)
            return $"No notes found matching '{keyword}'.";

        return $"Found {matches.Count} note(s) matching '{keyword}':\n\n" +
               string.Join("\n\n---\n\n",
                   matches.Select(n => $"**{n.Title}**\n{n.Content}"));
    }
}

