using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Service registration ---
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddHttpClient<WebSearchTool>();

var sp = services.BuildServiceProvider();

// --- Tools ---
var webSearch = sp.GetRequiredService<WebSearchTool>();
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>
{
    webSearch.AsAIFunction(),
};
tools.AddRange(noteTaking.AsAIFunctions());

// --- Build agent ---
var openAIClient = new OpenAIClient(apiKey);

IChatClient chatClient = new ChatClientBuilder(openAIClient.GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation(fic => fic.MaximumIterationsPerRequest = 10)
    .Build();

const string instructions = """
    You are a thorough research agent. Your job is to research a topic by:
    1. Searching the web for relevant information using multiple queries.
    2. Saving key findings as notes using the note-taking tools.
    3. After gathering enough information, retrieving all notes and producing
       a well-structured summary with key findings, different perspectives,
       and source attribution.

    Always save important findings as notes before summarizing.
    Use at least 2-3 different search queries to get comprehensive coverage.
    """;

var agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: tools);

// --- Interactive loop ---
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║          AI Research Agent                   ║");
Console.WriteLine("║  Type a topic to research, or 'quit' to exit║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.ResetColor();

